<div class="page-head"><div><h1>Student Records</h1><p>Manage academic information and enrollment status.</p></div><button class="btn primary" onclick="openModal('studentModal')">👥 Add New Student</button></div>
<div class="cards four"><div class="stat"><span class="icon">☻</span><small>Total Students</small><h2><?=$counts['total']?></h2></div><div class="stat"><span class="icon">✓</span><small>Active</small><h2><?=$counts['active']?></h2></div><div class="stat"><span class="icon">…</span><small>Pending Enrollment</small><h2><?=$counts['pending']?></h2></div><div class="stat danger"><span class="icon">!</span><small>At Risk</small><h2><?=$counts['risk']?></h2></div></div>
<section class="panel table-panel"><div class="panel-head"><h2>Enrollment List</h2><div><button onclick="exportTable('studentsTable')" class="icon-btn">⇩</button></div></div><table id="studentsTable"><thead><tr><th>Name</th><th>Email</th><th>Class</th><th>Status</th><th>Actions</th></tr></thead><tbody><?php foreach($students as $st):?><tr><td><div class="person"><div class="avatar"><?=strtoupper(substr($st['first_name'],0,1).substr($st['last_name'],0,1))?></div><div><b><?=htmlspecialchars($st['first_name'].' '.$st['last_name'])?></b><small>ID: #<?=htmlspecialchars($st['student_code'])?></small></div></div></td><td><?=htmlspecialchars($st['email'])?></td><td><?=htmlspecialchars($st['class_name'])?></td><td><span class="badge <?=strtolower(str_replace(' ','-',$st['status']))?>"><?=htmlspecialchars($st['status'])?></span></td><td><button class="link" onclick='editStudent(<?=json_encode($st)?>)'>Edit</button> <a class="link red" onclick="return confirm('Delete student?')" href="index.php?route=students.delete&id=<?=$st['id']?>">Delete</a></td></tr><?php endforeach;?></tbody></table></section>
<section class="panel chart-small"><h2>Enrollment Trends</h2><canvas id="barChart" height="180"></canvas></section>
<div class="modal" id="studentModal"><form class="modal-card" method="post" enctype="multipart/form-data" action="index.php?route=students.store"><input type="hidden" name="id" id="student_id"><h2 id="studentModalTitle">Add Student</h2><div class="form-grid"><input name="student_code" id="student_code" placeholder="Student code"><input name="first_name" id="first_name" placeholder="First name" required><input name="last_name" id="last_name" placeholder="Last name" required><input name="email" id="email" type="email" placeholder="Email"><input name="phone" id="phone" placeholder="Phone"><input name="class_name" id="class_name" placeholder="Class"><select name="status" id="status"><option>Active</option><option>Pending</option><option>Suspended</option><option>At Risk</option></select><input type="file" name="avatar"></div><div class="modal-actions"><button type="button" class="btn light" onclick="closeModal('studentModal')">Cancel</button><button class="btn primary">Save</button></div></form></div>
